5	
6	//! Typed-API host-closure smoke test.
7	//!
8	//! Drives the typed `#[cuda_module]` launch path with a generic kernel that
9	//! takes a closure. This exercises the kernel-boundary ABI fix that lets the
10	//! typed path push the closure as a single byval `.param` and have the
11	//! backend emit a single matching `.param` declaration. Before the fix this
12	//! example only worked through the call-site `cuda_launch!` macro because
13	//! that path pushed each capture individually; the typed API kept the
14	//! closure intact and mis-matched the backend's flattened ABI.
15	//!
16	//! Build and run with:
17	//!   cargo oxide run host_closure
18	//!
19	//! ## What it covers
20	//!
21	//! 1. Generic kernel with `Fn` trait bound: `fn map<T, F: Fn(T) -> T + Copy>(...)`
22	//! 2. Closures with 0, 1, 2, 3, 4 captures.
23	//! 3. Type inference of `F` at the call site (`module.map::<f32, _>(...)`).
24	//! 4. The closure is passed as a single byval struct — no per-capture flattening
25	//!    on either side.
26	//! 5. Equivalent coverage through sync and async typed and untyped launch paths.
27	//! 6. A where-clause `Fn` bound and layout-sensitive captures.
28	//! 7. `FnMut` and `FnOnce` trait bounds, so the device-side dispatch path is
29	//!    exercised for all three closure traits.
30	//! 8. Both reordered (default Rust repr, mixed-size fields) and identity-order
31	//!    (`#[repr(C)]`) struct captures.
32	
33	use cuda_async::device_operation::DeviceOperation;
34	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
35	use cuda_device::{DisjointSlice, kernel, thread};
36	use cuda_host::{cuda_launch, cuda_launch_async, cuda_module, load_kernel_module};
37	
38	#[derive(Clone, Copy)]
39	struct MixedCapture {
40	    small: u8,
41	    wide: f64,
42	    scale: f32,
43	}
44	
45	/// Same field set as [`MixedCapture`], but `#[repr(C)]` pins the layout to
46	/// declaration order (no rustc field reordering). The closure-layout fix has
47	/// to handle both the reordered and the identity-order cases, so we exercise
48	/// the identity path explicitly.
49	#[derive(Clone, Copy)]
50	#[repr(C)]
51	struct ReprCMixed {
52	    small: u8,
53	    wide: f64,
54	    scale: f32,
55	}
56	
57	// =============================================================================
58	// CLOSURE-ACCEPTING GENERIC KERNELS
59	// =============================================================================
60	#[cuda_module]
61	mod kernels {
62	    use super::*;
63	
64	    /// Generic map kernel — applies a function to each element.
65	    ///
66	    /// `F` is bound to the closure's anonymous type at the call site via
67	    /// the typed API's turbofish placeholder (`module.map::<f32, _>(...)`).
68	    /// The closure value itself is pushed as one byval kernel argument; the
69	    /// device reads it back as `F` and calls `f(input[idx])` on each thread.
70	    #[kernel]
71	    pub fn map<T: Copy, F: Fn(T) -> T + Copy>(f: F, input: &[T], mut out: DisjointSlice<T>) {
72	        let idx = thread::index_1d();
73	        let idx_raw = idx.get();
74	        if let Some(out_elem) = out.get_mut(idx) {
75	            *out_elem = f(input[idx_raw]);
76	        }
77	    }
78	
79	    /// Closure-generic kernel with a const parameter that cannot be inferred
80	    /// from its runtime arguments. This exercises explicit generic forwarding
81	    /// in both low-level launch macros.
82	    #[kernel]
83	    pub fn map_with_const<F, const OFFSET: u32>(f: F, input: &[u32], mut out: DisjointSlice<u32>)
84	    where
85	        F: Fn(u32) -> u32 + Copy,
86	    {
87	        let idx = thread::index_1d();
88	        let idx_raw = idx.get();
89	        if let Some(out_elem) = out.get_mut(idx) {
90	            *out_elem = f(input[idx_raw]) + OFFSET;
91	        }
92	    }
93	
94	    #[kernel]
95	    pub fn map_where<T, F>(f: F, input: &[T], mut out: DisjointSlice<T>)
96	    where
97	        T: Copy,
98	        F: Fn(T) -> T + Copy,
99	    {
100	        let idx = thread::index_1d();
101	        let idx_raw = idx.get();
102	        if let Some(out_elem) = out.get_mut(idx) {
103	            *out_elem = f(input[idx_raw]);
104	        }
105	    }
106	
107	    /// Same as [`map`] but with a `FnMut` trait bound, so the device-side
108	    /// dispatch goes through `<F as FnMut>::call_mut` instead of `Fn::call`.
109	    /// The closure is `Copy`, so each thread mutates its own register-resident
110	    /// copy of the closure environment.
111	    #[kernel]
112	    pub fn map_mut<T, F>(mut f: F, input: &[T], mut out: DisjointSlice<T>)
113	    where
114	        T: Copy,
115	        F: FnMut(T) -> T + Copy,
116	    {
117	        let idx = thread::index_1d();
118	        let idx_raw = idx.get();
119	        if let Some(out_elem) = out.get_mut(idx) {
120	            *out_elem = f(input[idx_raw]);
121	        }
122	    }
123	
124	    /// Same as [`map`] but with a `FnOnce` trait bound, so the device-side
125	    /// dispatch goes through `<F as FnOnce>::call_once` (which consumes the
126	    /// closure). The `Copy` bound lets the kernel re-invoke `call_once` per
127	    /// thread on a freshly-copied closure rather than running it exactly once.
128	    #[kernel]
129	    pub fn map_once<T, F>(f: F, input: &[T], mut out: DisjointSlice<T>)
130	    where
131	        T: Copy,
132	        F: FnOnce(T) -> T + Copy,
133	    {
134	        let idx = thread::index_1d();
135	        let idx_raw = idx.get();
136	        if let Some(out_elem) = out.get_mut(idx) {
137	            *out_elem = f(input[idx_raw]);
138	        }
139	    }
140	}
141	
142	fn verify_output(
143	    label: &str,
144	    output: &[f32],
145	    input: &[f32],
146	    tolerance: f32,
147	    expected: impl Fn(f32) -> f32,
148	    failed: &mut bool,
149	) {
150	    let errors = output
151	        .iter()
152	        .zip(input)
153	        .filter(|(got, x)| (**got - expected(**x)).abs() > tolerance)
154	        .count();
155	
156	    if errors == 0 {
157	        println!("  ✓ SUCCESS: {label}");
158	    } else {
159	        println!("  ✗ FAILED: {label}: {errors} errors");
160	        *failed = true;
161	        for (i, (&got, &x)) in output.iter().zip(input).take(5).enumerate() {
162	            let expected = expected(x);
163	            if (got - expected).abs() > tolerance {
164	                println!("    [{i}]: got {got}, expected {expected}");
165	            }
166	        }
167	    }
168	}
169	
170	// =============================================================================
171	// HOST CODE
172	// =============================================================================
173	
174	fn main() -> Result<(), Box<dyn std::error::Error>> {
175	    println!("=== Typed Closure Kernel Test ===\n");
176	
177	    let ctx = CudaContext::new(0)?;
178	    let stream = ctx.default_stream();
179	
180	    const N: usize = 1024;
181	    let input_data: Vec<f32> = (0..N).map(|i| i as f32).collect();
182	
183	    let input_dev = DeviceBuffer::from_host(&stream, &input_data)?;
184	    let mut output_dev: DeviceBuffer<f32>;
185	
186	    let module = load_kernel_module(&ctx, "host_closure")
187	        .map_err(|err| format!("failed to load host_closure kernel module: {err}"))?;
188	    let typed_module = kernels::from_module(module.clone())
189	        .map_err(|err| format!("failed to initialize typed host_closure module: {err}"))?;
190	    use kernels::*;
191	
192	    let mut failed = false;
193	
194	    macro_rules! run_launch_matrix {
195	        (
196	            $label:literal,
197	            $kernel:path,
198	            $typed_method:ident,
199	            $typed_async_method:ident,
200	            $closure:expr,
201	            $expected:expr,
202	            $tolerance:expr
203	        ) => {{
204	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
205	            // SAFETY: closure-then-slices matches every kernel this matrix
206	            // launches (closure env, input slice, output slice); both buffers
207	            // are live DeviceBuffers and the closure's captures are
208	            // host-accessible via HMM.
209	            unsafe {
210	                cuda_launch! {
211	                    kernel: $kernel,
212	                    stream: stream,
213	                    module: module,
214	                    config: LaunchConfig::for_num_elems(N as u32),
215	                    args: [$closure, slice(input_dev), slice_mut(output_dev)]
216	                }
217	            }?;
218	            let output_host = output_dev.to_host_vec(&stream)?;
219	            verify_output(
220	                concat!("cuda_launch ", $label),
221	                &output_host,
222	                &input_data,
223	                $tolerance,
224	                $expected,
225	                &mut failed,
226	            );
227	
228	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
229	            // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
230	            unsafe {
231	                typed_module.$typed_method::<f32, _>(
232	                    stream.as_ref(),
233	                    LaunchConfig::for_num_elems(N as u32),
234	                    $closure,
235	                    &input_dev,
236	                    &mut output_dev,
237	                )
238	            }?;
239	            let output_host = output_dev.to_host_vec(&stream)?;
240	            verify_output(
241	                concat!("typed launch ", $label),
242	                &output_host,
243	                &input_data,
244	                $tolerance,
245	                $expected,
246	                &mut failed,
247	            );
248	
249	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
250	            // SAFETY: this is a 1D launch and each kernel guards its 1D index
251	            // against the length carried by the output slice.
252	            unsafe {
253	                cuda_launch_async! {
254	                    kernel: $kernel,
255	                    module: module,
256	                    config: LaunchConfig::for_num_elems(N as u32),
257	                    args: [$closure, slice(input_dev), slice_mut(output_dev)]
258	                }
259	            }
260	            .sync_on(&stream)?;
261	            let output_host = output_dev.to_host_vec(&stream)?;
262	            verify_output(
263	                concat!("cuda_launch_async ", $label),
264	                &output_host,
265	                &input_data,
266	                $tolerance,
267	                $expected,
268	                &mut failed,
269	            );
270	
271	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
272	            // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
273	            unsafe {
274	                typed_module.$typed_async_method::<f32, _>(
275	                    LaunchConfig::for_num_elems(N as u32),
276	                    $closure,
277	                    &input_dev,
278	                    &mut output_dev,
279	                )
280	            }?
281	            .sync_on(&stream)?;
282	            let output_host = output_dev.to_host_vec(&stream)?;
283	            verify_output(
284	                concat!("typed async launch ", $label),
285	                &output_host,
286	                &input_data,
287	                $tolerance,
288	                $expected,
289	                &mut failed,
290	            );
291	        }};
292	    }
293	
294	    // =========================================================================
295	    // TEST 1: Closure with single capture
296	    // =========================================================================
297	    println!("Test 1: Single capture (scale by factor)");
298	    {
299	        let factor = 2.5f32;
300	        println!("  factor = {}", factor);
301	        println!("  N = {}", N);
302	
303	        run_launch_matrix!(
304	            "single capture",
305	            map::<f32, _>,
306	            map,
307	            map_async,
308	            move |x: f32| x * factor,
309	            |x| x * factor,
310	            1e-5
311	        );
312	        println!();
313	    }
314	
315	    // =========================================================================
316	    // TEST 2: Closure with multiple captures
317	    // =========================================================================
318	    println!("Test 2: Multiple captures (affine transform)");
319	    {
320	        let scale = 2.0f32;
321	        let offset = 10.0f32;
322	        println!("  scale = {}, offset = {}", scale, offset);
323	
324	        run_launch_matrix!(
325	            "multiple captures",
326	            map::<f32, _>,
327	            map,
328	            map_async,
329	            move |x: f32| x * scale + offset,
330	            |x| x * scale + offset,
331	            1e-5
332	        );
333	        println!();
334	    }
335	
336	    // =========================================================================
337	    // TEST 3: Zero-capture closure (inline constant)
338	    // =========================================================================
339	    println!("Test 3: Zero captures (double each element)");
340	    {
341	        run_launch_matrix!(
342	            "zero-capture closure",
343	            map::<f32, _>,
344	            map,
345	            map_async,
346	            |x: f32| x * 2.0,
347	            |x| x * 2.0,
348	            1e-5
349	        );
350	        println!();
351	    }
352	
353	    // =========================================================================
354	    // TEST 4: Closure with 3 captures (polynomial transform)
355	    // =========================================================================
356	    println!("Test 4: Three captures (polynomial: a*x^2 + b*x + c)");
357	    {
358	        let a = 0.5f32;
359	        let b = 2.0f32;
360	        let c = 1.0f32;
361	        println!("  a = {}, b = {}, c = {}", a, b, c);
362	
363	        run_launch_matrix!(
364	            "three captures",
365	            map::<f32, _>,
366	            map,
367	            map_async,
368	            move |x: f32| a * x * x + b * x + c,
369	            |x| a * x * x + b * x + c,
370	            1e-3
371	        );
372	        println!();
373	    }
374	
375	    // =========================================================================
376	    // TEST 5: Closure with 4 captures (to ensure arbitrary count works)
377	    // =========================================================================
378	    println!("Test 5: Four captures (weighted sum: w1*x + w2 + w3*w4)");
379	    {
380	        let w1 = 3.0f32;
381	        let w2 = 5.0f32;
382	        let w3 = 2.0f32;
383	        let w4 = 7.0f32;
384	        println!("  w1 = {}, w2 = {}, w3 = {}, w4 = {}", w1, w2, w3, w4);
385	
386	        run_launch_matrix!(
387	            "four captures",
388	            map::<f32, _>,
389	            map,
390	            map_async,
391	            move |x: f32| w1 * x + w2 + w3 * w4,
392	            |x| w1 * x + w2 + w3 * w4,
393	            1e-3
394	        );
395	        println!();
396	    }
397	
398	    // =========================================================================
399	    // TEST 6: where-clause Fn bound
400	    // =========================================================================
401	    println!("Test 6: where-clause Fn bound");
402	    {
403	        let scale = 1.5f32;
404	        let bias = 4.0f32;
405	        println!("  scale = {}, bias = {}", scale, bias);
406	
407	        run_launch_matrix!(
408	            "where-clause Fn bound",
409	            map_where::<f32, _>,
410	            map_where,
411	            map_where_async,
412	            move |x: f32| x * scale - bias,
413	            |x| x * scale - bias,
414	            1e-5
415	        );
416	        println!();
417	    }
418	
419	    // =========================================================================
420	    // TEST 7: mixed-size captures
421	    // =========================================================================
422	    println!("Test 7: mixed-size captures");
423	    {
424	        let small = 7u8;
425	        let scale = 1.25f32;
426	        let wide = 3.5f64;
427	        println!("  small = {}, scale = {}, wide = {}", small, scale, wide);
428	
429	        run_launch_matrix!(
430	            "mixed-size captures",
431	            map::<f32, _>,
432	            map,
433	            map_async,
434	            move |x: f32| x * scale + wide as f32 + small as f32,
435	            |x| x * scale + wide as f32 + small as f32,
436	            1e-5
437	        );
438	        println!();
439	    }
440	
441	    // =========================================================================
442	    // TEST 8: struct capture with internal padding
443	    // =========================================================================
444	    println!("Test 8: struct capture with internal padding");
445	    {
446	        let mixed = MixedCapture {
447	            small: 9,
448	            wide: 2.25,
449	            scale: 0.75,
450	        };
451	        println!(
452	            "  small = {}, scale = {}, wide = {}",
453	            mixed.small, mixed.scale, mixed.wide
454	        );
455	
456	        run_launch_matrix!(
457	            "struct capture with internal padding",
458	            map::<f32, _>,
459	            map,
460	            map_async,
461	            move |x: f32| x * mixed.scale + mixed.wide as f32 + mixed.small as f32,
462	            |x| x * mixed.scale + mixed.wide as f32 + mixed.small as f32,
463	            1e-5
464	        );
465	        println!();
466	    }
467	
468	    // =========================================================================
469	    // TEST 9: non-move reference captures
470	    // =========================================================================
471	    //
472	    // NOTE: this case relies on Heterogeneous Memory Management. Without
473	    // `move`, the closure environment holds `&f32` pointers into the host
474	    // stack frame of `main`; the GPU dereferences those pointers at kernel
475	    // entry. Working configurations need an HMM-capable GPU (sm_75+ on
476	    // Linux) with HMM enabled in the driver. On systems without HMM this
477	    // surfaces as `CUDA_ERROR_ILLEGAL_ADDRESS` from the launch, which the
478	    // smoketest's `verdict_standard` correctly flags as FAIL.
479	    println!("Test 9: non-move reference captures");
480	    {
481	        let scale = 0.5f32;
482	        let bias = 8.0f32;
483	        println!("  scale = {}, bias = {}", scale, bias);
484	        println!("  captures are borrowed by the closure environment");
485	
486	        run_launch_matrix!(
487	            "non-move reference captures",
488	            map::<f32, _>,
489	            map,
490	            map_async,
491	            |x: f32| x * scale + bias,
492	            |x| x * scale + bias,
493	            1e-5
494	        );
495	        println!();
496	    }
497	
498	    // =========================================================================
499	    // TEST 10: FnMut bound — different device-side dispatch from Fn
500	    // =========================================================================
501	    println!("Test 10: FnMut bound (multi-capture)");
502	    {
503	        let scale = 1.5f32;
504	        let offset = 6.0f32;
505	        println!("  scale = {}, offset = {}", scale, offset);
506	
507	        run_launch_matrix!(
508	            "FnMut bound, multi-capture",
509	            map_mut::<f32, _>,
510	            map_mut,
511	            map_mut_async,
512	            move |x: f32| x * scale + offset,
513	            |x| x * scale + offset,
514	            1e-5
515	        );
516	        println!();
517	    }
518	
519	    // =========================================================================
520	    // TEST 11: FnOnce bound — call_once dispatch with Copy
521	    // =========================================================================
522	    println!("Test 11: FnOnce bound (multi-capture, Copy closure)");
523	    {
524	        let weight = 2.25f32;
525	        let intercept = 12.5f32;
526	        println!("  weight = {}, intercept = {}", weight, intercept);
527	
528	        run_launch_matrix!(
529	            "FnOnce bound, multi-capture",
530	            map_once::<f32, _>,
531	            map_once,
532	            map_once_async,
533	            move |x: f32| x * weight + intercept,
534	            |x| x * weight + intercept,
535	            1e-5
536	        );
537	        println!();
538	    }
539	
540	    // =========================================================================
541	    // TEST 12: #[repr(C)] struct capture (identity-order layout)
542	    // =========================================================================
543	    // Counterpart to test 8: the layout fix has to handle both the reordered
544	    // case (default Rust repr, fields packed by size) and the identity-order
545	    // case (`#[repr(C)]`, fields kept in declaration order). The closure
546	    // body is the same as test 8 so the expected output is comparable.
547	    println!("Test 12: #[repr(C)] struct capture (identity-order layout)");
548	    {
549	        let mixed = ReprCMixed {
550	            small: 9,
551	            wide: 2.25,
552	            scale: 0.75,
553	        };
554	        println!(
555	            "  small = {}, scale = {}, wide = {}",
556	            mixed.small, mixed.scale, mixed.wide
557	        );
558	
559	        run_launch_matrix!(
560	            "repr(C) struct capture",
561	            map::<f32, _>,
562	            map,
563	            map_async,
564	            move |x: f32| x * mixed.scale + mixed.wide as f32 + mixed.small as f32,
565	            |x| x * mixed.scale + mixed.wide as f32 + mixed.small as f32,
566	            1e-5
567	        );
568	        println!();
569	    }
570	
571	    // =========================================================================
572	    // TEST 13: Closure type inference plus an explicit const argument
573	    // =========================================================================
574	    println!("Test 13: closure plus const-generic specialization");
575	    {
576	        let input: Vec<u32> = (0..N as u32).collect();
577	        let input_dev_u32 = DeviceBuffer::from_host(&stream, &input)?;
578	        let factor = 3u32;
579	
580	        let mut output_4 = DeviceBuffer::<u32>::zeroed(&stream, N)?;
581	        unsafe {
582	            cuda_launch! {
583	                kernel: kernels::map_with_const::<_, 4>,
584	                stream: stream,
585	                module: module,
586	                config: LaunchConfig::for_num_elems(N as u32),
587	                args: [move |x: u32| x * factor, slice(input_dev_u32), slice_mut(output_4)]
588	            }
589	        }?;
590	        let result_4 = output_4.to_host_vec(&stream)?;
591	        assert!((0..N).all(|i| result_4[i] == input[i] * factor + 4));
592	
593	        let mut output_8 = DeviceBuffer::<u32>::zeroed(&stream, N)?;
594	        // SAFETY: `map_with_const` uses a guarded 1D index and this config has
595	        // no active Y or Z dimensions.
596	        unsafe {
597	            cuda_launch_async! {
598	                kernel: kernels::map_with_const::<_, 8>,
599	                module: module,
600	                config: LaunchConfig::for_num_elems(N as u32),
601	                args: [move |x: u32| x * factor, slice(input_dev_u32), slice_mut(output_8)]
602	            }
603	        }
604	        .sync_on(&stream)?;
605	        let result_8 = output_8.to_host_vec(&stream)?;
606	        assert!((0..N).all(|i| result_8[i] == input[i] * factor + 8));
607	
608	        println!("  ✓ SUCCESS: sync and async launch macros forwarded OFFSET");
609	    }
610	
611	    println!("=== All Tests Complete ===");
612	    if failed {
613	        Err("one or more host_closure tests failed".into())
614	    } else {
615	        Ok(())
616	    }
617	}
