28	
29	// =============================================================================
30	// GENERIC KERNELS
31	// =============================================================================
32	
33	/// Generic scale kernel - multiplies each element by a factor.
34	///
35	/// This kernel is generic over T. Each typed module method call
36	/// monomorphizes it to a concrete device entry point.
37	#[allow(dead_code)]
38	#[cuda_module]
39	mod kernels {
40	    use super::*;
41	
42	    #[kernel]
43	    pub fn scale<T: Copy + Mul<Output = T>>(factor: T, input: &[T], mut out: DisjointSlice<T>) {
44	        let idx = thread::index_1d();
45	        let idx_raw = idx.get();
46	        if let Some(out_elem) = out.get_mut(idx) {
47	            *out_elem = input[idx_raw] * factor;
48	        }
49	    }
50	
51	    /// Generic add kernel - adds two arrays element-wise.
52	    #[kernel]
53	    pub fn add<T: Copy + Add<Output = T>>(a: &[T], b: &[T], mut c: DisjointSlice<T>) {
54	        let idx = thread::index_1d();
55	        let idx_raw = idx.get();
56	        if let Some(c_elem) = c.get_mut(idx) {
57	            *c_elem = a[idx_raw] + b[idx_raw];
58	        }
59	    }
60	
61	    #[inline(never)]
62	    fn apply_unary<T, F>(f: F, x: T) -> T
63	    where
64	        F: FnOnce(T) -> T,
65	    {
66	        f(x)
67	    }
68	
69	    /// Generic kernel whose body defines a captured closure.
70	    ///
71	    /// rustc prepends the parent generic args before a closure's fixed
72	    /// `[kind, sig, tupled_upvars]` suffix. The importer must read the upvars
73	    /// tuple from the suffix, not from a hard-coded substitution index.
74	    #[kernel]
75	    pub fn closure_capture<T>(bias: T, scale: T, input: &[T], mut out: DisjointSlice<T>)
76	    where
77	        T: Copy + Add<Output = T> + Mul<Output = T>,
78	    {
79	        let idx = thread::index_1d();
80	        let idx_raw = idx.get();
81	        if let Some(out_elem) = out.get_mut(idx) {
82	            let transform = move |x: T| (x + bias) * scale;
83	            *out_elem = apply_unary(transform, input[idx_raw]);
84	        }
85	    }
86	}
