88	// =============================================================================
89	// HOST CODE
90	// =============================================================================
91	//
92	// Calling the typed module method with type parameters triggers monomorphization.
93	
94	fn main() {
95	    println!("=== Unified Generic Kernel Test ===\n");
96	
97	    // Initialize CUDA
98	    let ctx = CudaContext::new(0).expect("Failed to create CUDA context");
99	    let stream = ctx.default_stream();
100	
101	    const N: usize = 1024;
102	    let module = kernels::load(&ctx).expect("Failed to load embedded CUDA module");
103	
104	    // =========================================================================
105	    // THE KEY: typed method call with type parameter forces monomorphization!
106	    // =========================================================================
107	    //
108	    // module.scale::<f32>(...) expands to code that references
109	    // cuda_oxide_kernel_scale::<f32>, forcing rustc to monomorphize it and
110	    // making it visible to the backend's collector.
111	
112	    println!("\nLaunching scale::<f32> kernel...");
113	    {
114	        let factor: f32 = 2.5;
115	        let input_data: Vec<f32> = (0..N).map(|i| i as f32).collect();
116	        let input_dev =
117	            DeviceBuffer::from_host(&stream, &input_data).expect("Failed to copy f32 input");
118	        let mut output_dev =
119	            DeviceBuffer::<f32>::zeroed(&stream, N).expect("Failed to alloc f32 output");
120	
121	        // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
122	        unsafe {
123	            module.scale::<f32>(
124	                &stream,
125	                LaunchConfig::for_num_elems(N as u32),
126	                factor,
127	                &input_dev,
128	                &mut output_dev,
129	            )
130	        }
131	        .expect("scale::<f32> launch failed");
132	
133	        let output_host = output_dev
134	            .to_host_vec(&stream)
135	            .expect("Failed to copy f32 output back");
136	        let errors = (0..N)
