30	use core::any::TypeId;
31	use std::{
32	    collections::HashMap,
33	    sync::{Mutex, OnceLock},
34	};
35	
36	type KernelNameKey = (&'static str, u128);
37	
38	static GENERIC_KERNEL_NAMES: OnceLock<Mutex<HashMap<KernelNameKey, &'static str>>> =
39	    OnceLock::new();
40	
41	/// Returns the same 128-bit hash that the cuda-oxide backend uses for
42	/// kernel export names.
43	///
44	/// At runtime the value is just the 16 raw hash bytes (see the layout
45	/// comment in `core::any::TypeId`). The intrinsic is const-evaluated by
46	/// rustc using its internal `Ty<'tcx>` representation, so the call site
47	/// only ever sees a constant `u128`.
48	///
49	/// Bound is intentionally `T: ?Sized` (not `T: 'static`). The typed launch
50	/// path must keep accepting non-`'static` borrowing closures, the same way
51	/// the legacy `type_name`-based path did. Adding `'static` here would
52	/// silently tighten the typed API without enforcing the actual launch-
53	/// outlives-borrow invariant — that responsibility still sits with the
54	/// caller (the borrow must outlive `stream.synchronize()`).
55	#[inline]
56	pub fn type_id_u128<T: ?Sized>() -> u128 {
57	    let id = const { core::intrinsics::type_id::<T>() };
58	    unsafe { core::mem::transmute::<TypeId, u128>(id) }
59	}
60	
61	/// Returns [`type_id_u128`] for the inferred type of `value`.
62	///
63	/// This is primarily useful for function items, whose anonymous type cannot be
64	/// written in a turbofish. For example, `type_id_u128_of_val(&kernel::<T, 4>)`
65	/// hashes the concrete `kernel::<T, 4>` function-item type rather than its
66	/// coerced function-pointer signature. Keeping the item uncoerced is important:
67	/// the item type retains both the function definition and its generic arguments.
68	#[inline]
69	pub fn type_id_u128_of_val<T: ?Sized>(_: &T) -> u128 {
70	    type_id_u128::<T>()
71	}
72	
73	/// Interns the PTX lookup name for one generic kernel specialization.
74	///
75	/// This is public only because `#[kernel]` expansions in downstream crates
76	/// call it. The process-wide table allocates once per `(base_name, type_hash)`
77	/// pair; repeated launches reuse the same `&'static str` instead of leaking a
78	/// fresh formatted name on every cache lookup.
79	#[doc(hidden)]
80	pub fn __intern_generic_kernel_name(base_name: &'static str, type_hash: u128) -> &'static str {
81	    let names = GENERIC_KERNEL_NAMES.get_or_init(|| Mutex::new(HashMap::new()));
82	    let mut names = names
83	        .lock()
84	        .unwrap_or_else(|poisoned| poisoned.into_inner());
85	    match names.entry((base_name, type_hash)) {
86	        std::collections::hash_map::Entry::Occupied(entry) => entry.get(),
87	        std::collections::hash_map::Entry::Vacant(entry) => {
88	            let name: &'static str =
89	                Box::leak(format!("{base_name}_TID_{type_hash:032x}").into_boxed_str());
90	            entry.insert(name);
91	            name
92	        }
93	    }
